// Home.js
import { useNavigate } from 'react-router-dom';
import React, { useState, useEffect } from 'react';
import { FaRocket } from "react-icons/fa";
import axios from 'axios';
import Charts from "./components/Charts";
import './Home.css';

function Home() {
  const [showProfile, setShowProfile] = useState(false);
  const [user, setUser] = useState(null);
  const navigate = useNavigate();

  // Stats for dashboard cards
  const [stats, setStats] = useState({
    totalPredictions: 0,
    avgSalary: 0,
    bestModelAccuracy: 0
  });

  // Logout function
  const handleLogout = () => {
    localStorage.clear();
    navigate('/login');
  };

  useEffect(() => {
    const storedUser = localStorage.getItem("user");

    if (storedUser) {
      const userData = JSON.parse(storedUser);
      setUser(userData);

      // Total Predictions API
      axios.get(`http://localhost:5000/stats/${userData.email}`)
        .then(res => {
          setStats(prev => ({
            ...prev,
            totalPredictions: res.data.totalPredictions || 0
          }));
        })
        .catch(err => console.log(err));

      // Average Salary API
      axios.get(`http://localhost:5000/api/average-salary/${userData.email}`)
        .then(res => {
          setStats(prev => ({
            ...prev,
            avgSalary: res.data.average || 0
          }));
        })
        .catch(err => console.log(err));

      // Best Model Accuracy API (optional, hardcoded if not ready)
      axios.get(`http://localhost:5000/api/best-model-accuracy`)
        .then(res => {
          setStats(prev => ({
            ...prev,
            bestModelAccuracy: res.data.accuracy || 0
          }));
        })
        .catch(err => console.log(err));

    } else {
      navigate('/login');
    }
  }, [navigate]);

  return (
    <div className="home-container">

      {/* NAVBAR */}
      <nav className="navbar">
        <h3>Dashboard</h3>

        <div className="right-section">
          <div
            className="profile-circle"
            onClick={() => setShowProfile(!showProfile)}
          >
            <span>{user?.name?.charAt(0) || "P"}</span>
          </div>

          {showProfile && (
            <div className="profile-card">
              <h3>Profile 👤</h3>
              <p><b>Name:</b> {user?.name}</p>
              <p><b>Email:</b> {user?.email}</p>
              <p><b>Password:</b> ********</p>
            </div>
          )}

          <button onClick={handleLogout} className="logout-btn">
            Logout
          </button>
        </div>
      </nav>

      {/* MAIN CONTENT */}
      <div className="main-content">
        {/* SLOGAN */}
        <h2 className="slogan">Know Your Worth, Predict With Confidence 🚀</h2>
            <div className="predict-btn-container">
        <button
          className="new-prediction-btn"
          onClick={() => navigate('/predict')}
        >
          <FaRocket style={{ marginRight: "8px" }} />
          New Salary Prediction
        </button>
        </div>

        {/* STATS CARDS */}
        <div className="stats-container">

          {/* TOTAL PREDICTIONS */}
          <div className="stat-card" onClick={() => navigate("/my-history")}>
            <h3>Total Predictions</h3>
            <p>{stats.totalPredictions}</p>
          </div>

          {/* AVERAGE SALARY */}
          <div className="stat-card" onClick={() => navigate("/average-salary")}>
            <h3>Average Salary</h3>
            <p>
              {stats.avgSalary
                ? `₹${(stats.avgSalary / 100000).toFixed(1)} LPA`
                : "Loading..."}
            </p>
          </div>

          {/* BEST MODEL ACCURACY */}
          <div className="stat-card">
            <h3>Best Model Accuracy</h3>
            <p>{stats.bestModelAccuracy}%</p>
          </div>

        </div>

        {/* CHART COMPONENT */}
        <div style={{ marginTop: "40px" }}>
          <Charts />
        </div>

      </div>
    </div>
  );
}

export default Home;
